// 【VIP规则：低速占坑清理】（替代原智能慢车清理）
(maindata, torrent) => {
  const categoryList = ["不删", "keep"];
  const { state, upspeed, category } = torrent.originProp;

  if (categoryList.indexOf(category) !== -1 || torrent.leecher >= 100) {
    return false;
  }

  // 保护期：凌晨不删，或者当前处于抢种初期的总下载任务较少（15个以内）时不删
  if (
    (moment().hour() >= 0 && moment().hour() <= 7) ||
    maindata.leechingCount <= 15
  ) {
    return false;
  }

  // 执行：处于下载阶段，且添加超过 15 分钟（900秒，给足时间去连接吸血鬼），如果上传速度依然死皮赖脸低于 500KB/s，处决。
  // （阈值 500KiB 可根据你的刷流机器和宽带自行判断去调高或调低）
  if (
    (state === "downloading" || state === "forcedDL" || state === "stalledDL" || state === "allocating") &&
    upspeed <= util.calSize(500, "KiB") &&
    moment().unix() - torrent.addedTime >= 900
  ) {
    return true; 
  }

  return false;
};
